  1  /**
  2   * @file main.c
  3   * @brief ILI9488 Color Fill Demo
  4   *
  5   * Cycles through solid colors on a 320x480 ILI9488 display connected to a Raspberry Pi 4B via SPI0:
  6   *   SPI device : /dev/spidev0.0  (10 MHz)
  7   *   RESET GPIO : BCM 24 (Pin 18)
  8   *   D/C GPIO   : BCM 25 (Pin 22)
  9   *   CS         : BCM  8 / SPI0_CE0 (Pin 24) -- handled by spidev
 10   *
 11   * AI Usage Disclaimer: This file was mostly outlined then generated using AI tools. See ./AI_chats for the full conversation logs as best as could be exported.
 12   */
 13
 14   // Note: Next ToDo: Update demo to use framebuffer API, doing a dirty region animation with color changes to show smearing and moving in a square
 15   // Also ToDo: Add something to do the single pixel draw demo
 16   // After ToDo: Add Line drawing to demo
 17   // Then ToDo: Add text drawing library, then add text to demo
 18   // Final ToDo: Review and clean up all code, finalize comments and documentation (readme and wiki), and prepare for final project submission
 19
 20  #include "ili9488_gfx.h"
 21  #include "ili9488_hal.h"
 22  #include <stdio.h>
 23  #include <stdlib.h>
 24  #include <time.h>
 25  #include <unistd.h>
 26
 27
 28  /* RGB565 color values */
 29  #define COLOR_RED     0xF800U
 30  #define COLOR_GREEN   0x07E0U
 31  #define COLOR_BLUE    0x001FU
 32  #define COLOR_WHITE   0xFFFFU
 33  #define COLOR_BLACK   0x0000U
 34  #define COLOR_YELLOW  0xFFE0U
 35  #define COLOR_CYAN    0x07FFU
 36  #define COLOR_MAGENTA 0xF81FU
 37  #define COLOR_ORANGE  0xFD20U
 38  #define COLOR_PURPLE  0x8010U
 39  #define COLOR_LIME    0x87E0U
 40  #define COLOR_SILVER  0xC618U
 41
 42  #define DISPLAY_WIDTH  ILI9488_GFX_DEFAULT_WIDTH
 43  #define DISPLAY_HEIGHT ILI9488_GFX_DEFAULT_HEIGHT
 44
 45  #ifndef DEMO_DEBUG_PRINTS
 46  #define DEMO_DEBUG_PRINTS 0
 47  #endif
 48
 49  #if DEMO_DEBUG_PRINTS
 50  #define DEMO_DEBUG_PRINTF(...) printf(__VA_ARGS__)
 51  #else
 52  #define DEMO_DEBUG_PRINTF(...) ((void)0)
 53  #endif
 54
 55  #define FRAME_DELAY_MS 200U
 56  #define DIRTY_BOX_SIZE 108U
 57  #define PATH_MARGIN    24U
 58  #define STEP_PIXELS    12U
 59
 60  #define FULL_FILL_HOLD_MS         170U
 61  #define FULL_FILL_SHOW_COUNT      2U
 62
 63  #define STARBURST_SHORT_RAYS      36U
 64  #define STARBURST_LONG_RAYS       36U
 65  #define STARBURST_RAYS_TOTAL      (STARBURST_SHORT_RAYS + STARBURST_LONG_RAYS)
 66
 67  typedef enum {
 68      DEMO_PHASE_RECTANGLE = 0,
 69      DEMO_PHASE_FILLS_AFTER_RECT,
 70      DEMO_PHASE_STARBURST,
 71      DEMO_PHASE_FILLS_AFTER_STARBURST
 72  } demo_phase_t;
 73
 74  static uint64_t monotonic_time_ms(void)
 75  {
 76      struct timespec ts;
 77      if (clock_gettime(CLOCK_MONOTONIC, &ts) != 0) {
 78          return 0U;
 79      }
 80
 81      return ((uint64_t)ts.tv_sec * 1000U) + ((uint64_t)ts.tv_nsec / 1000000U);
 82  }
 83
 84  static void sleep_remaining_frame(uint64_t frame_start_ms, uint32_t frame_target_ms)
 85  {
 86      uint64_t frame_end_ms = monotonic_time_ms();
 87      if (frame_end_ms <= frame_start_ms) {
 88          usleep(frame_target_ms * 1000U);
 89          return;
 90      }
 91
 92      uint64_t elapsed_ms = frame_end_ms - frame_start_ms;
 93      if (elapsed_ms < frame_target_ms) {
 94          uint64_t remaining_ms = frame_target_ms - elapsed_ms;
 95          usleep((useconds_t)(remaining_ms * 1000U));
 96      }
 97  }
 98
 99  static void rectangle_position_from_distance(uint32_t distance,
100                                               uint16_t left,
101                                               uint16_t top,
102                                               uint16_t right,
103                                               uint16_t bottom,
104                                               uint16_t *x,
105                                               uint16_t *y)
106  {
107      uint32_t horizontal_span = (uint32_t)(right - left);
108      uint32_t vertical_span = (uint32_t)(bottom - top);
109
110      if (distance <= horizontal_span) {
111          *x = (uint16_t)(left + distance);
112          *y = top;
113      } else if (distance <= (horizontal_span + vertical_span)) {
114          *x = right;
115          *y = (uint16_t)(top + (distance - horizontal_span));
116      } else if (distance <= (2U * horizontal_span + vertical_span)) {
117          *x = (uint16_t)(right - (distance - (horizontal_span + vertical_span)));
118          *y = bottom;
119      } else {
120          *x = left;
121          *y = (uint16_t)(bottom - (distance - (2U * horizontal_span + vertical_span)));
122      }
123  }
124
125  int main(void)
126  {
127      DEMO_DEBUG_PRINTF("ILI9488 Demo\n");
128
129      if (!hal_display_initialize(PIXEL_FORMAT_18BIT, ROTATION_0_NORMAL)) {
130          fprintf(stderr, "Error: display initialisation failed\n");
131          return EXIT_FAILURE;
132      }
133
134      DEMO_DEBUG_PRINTF("Display ready -- starting dirty-region smear demo\n");
135
136      size_t fb_pixels = gfx_framebuffer_required_pixels(DISPLAY_WIDTH, DISPLAY_HEIGHT);
137      if (fb_pixels == 0U) {
138          fprintf(stderr, "Error: invalid framebuffer dimensions\n");
139          hal_display_deinitialize();
140          return EXIT_FAILURE;
141      }
142
143      uint16_t *fb_storage = (uint16_t *)malloc(fb_pixels * sizeof(uint16_t));
144      if (fb_storage == NULL) {
145          fprintf(stderr, "Error: framebuffer allocation failed\n");
146          hal_display_deinitialize();
147          return EXIT_FAILURE;
148      }
149
150      gfx_framebuffer_t framebuffer;
151      if (!gfx_framebuffer_bind(&framebuffer,
152                                fb_storage,
153                                fb_pixels,
154                                DISPLAY_WIDTH,
155                                DISPLAY_HEIGHT,
156                                0U)) {
157          fprintf(stderr, "Error: framebuffer bind failed\n");
158          free(fb_storage);
159          hal_display_deinitialize();
160          return EXIT_FAILURE;
161      }
162
163      if (!gfx_fill(&framebuffer, COLOR_BLACK) || !gfx_flush(&framebuffer)) {
164          fprintf(stderr, "Error: initial framebuffer clear/flush failed\n");
165          gfx_framebuffer_unbind(&framebuffer);
166          free(fb_storage);
167          hal_display_deinitialize();
168          return EXIT_FAILURE;
169      }
170
171      static const struct {
172          uint16_t    color;
173          const char *name;
174      } colors[] = {
175          { COLOR_RED,     "Red"     },
176          { COLOR_GREEN,   "Green"   },
177          { COLOR_BLUE,    "Blue"    },
178          { COLOR_WHITE,   "White"   },
179          { COLOR_BLACK,   "Black"   },
180          { COLOR_YELLOW,  "Yellow"  },
181          { COLOR_CYAN,    "Cyan"    },
182          { COLOR_MAGENTA, "Magenta" },
183          { COLOR_ORANGE,  "Orange"  },
184          { COLOR_PURPLE,  "Purple"  },
185          { COLOR_LIME,    "Lime"    },
186          { COLOR_SILVER,  "Silver"  }
187      };
188
189      int color_count = (int)(sizeof(colors) / sizeof(colors[0]));
190
191      uint16_t path_left = PATH_MARGIN;
192      uint16_t path_top = PATH_MARGIN;
193      uint16_t path_right = DISPLAY_WIDTH - PATH_MARGIN - DIRTY_BOX_SIZE;
194      uint16_t path_bottom = DISPLAY_HEIGHT - PATH_MARGIN - DIRTY_BOX_SIZE;
195
196      if (path_right <= path_left || path_bottom <= path_top) {
197          fprintf(stderr, "Error: dirty region path does not fit display\n");
198          gfx_framebuffer_unbind(&framebuffer);
199          free(fb_storage);
200          hal_display_deinitialize();
201          return EXIT_FAILURE;
202      }
203
204      uint16_t box_x = path_left;
205      uint16_t box_y = path_top;
206      int color_index = 0;
207      int pixel_color_index = 0;
208
209      uint16_t pixel_x = DISPLAY_WIDTH / 2U;
210      uint16_t pixel_y = DISPLAY_HEIGHT / 2U;
211      int16_t pixel_dx = (int16_t)STEP_PIXELS;
212      int16_t pixel_dy = (int16_t)STEP_PIXELS;
213      demo_phase_t phase = DEMO_PHASE_RECTANGLE;
214      unsigned int phase_step = 0U;
215      unsigned int fill_color_cursor = 0U;
216      bool starburst_phase_started = false;
217
218      uint16_t center_x = DISPLAY_WIDTH / 2U;
219      uint16_t center_y = DISPLAY_HEIGHT / 2U;
220
221      uint16_t long_left = 0U;
222      uint16_t long_top = 0U;
223      uint16_t long_right = DISPLAY_WIDTH - 1U;
224      uint16_t long_bottom = DISPLAY_HEIGHT - 1U;
225      uint32_t long_perimeter = 2U * ((uint32_t)(long_right - long_left) + (uint32_t)(long_bottom - long_top));
226
227      uint16_t short_half_width = DISPLAY_WIDTH / 8U;
228      uint16_t short_half_height = DISPLAY_HEIGHT / 8U;
229      uint16_t short_left = center_x - short_half_width;
230      uint16_t short_top = center_y - short_half_height;
231      uint16_t short_right = center_x + short_half_width;
232      uint16_t short_bottom = center_y + short_half_height;
233      uint32_t short_perimeter = 2U * ((uint32_t)(short_right - short_left) + (uint32_t)(short_bottom - short_top));
234
235      uint32_t rect_horizontal_span = (uint32_t)(path_right - path_left);
236      uint32_t rect_vertical_span = (uint32_t)(path_bottom - path_top);
237      uint32_t rect_perimeter = 2U * (rect_horizontal_span + rect_vertical_span);
238      uint32_t rect_start_distance = 0U;
239      uint32_t rect_distance = rect_start_distance;
240      uint32_t rect_travelled = 0U;
241
242      if (rect_perimeter == 0U) {
243          fprintf(stderr, "Error: rectangle perimeter is zero\n");
244          gfx_framebuffer_unbind(&framebuffer);
245          free(fb_storage);
246          hal_display_deinitialize();
247          return EXIT_FAILURE;
248      }
249
250      while (1) {
251          uint64_t frame_start_ms = monotonic_time_ms();
252          bool apply_frame_pacing = true;
253
254          switch (phase) {
255          case DEMO_PHASE_RECTANGLE: {
256              rectangle_position_from_distance(rect_distance,
257                                               path_left,
258                                               path_top,
259                                               path_right,
260                                               path_bottom,

260                                               path_bottom,
261                                               &box_x,
262                                               &box_y);
263
264              uint16_t box_x2 = box_x + DIRTY_BOX_SIZE - 1U;
265              uint16_t box_y2 = box_y + DIRTY_BOX_SIZE - 1U;
266
267              if (!gfx_draw_filled_rectangle(&framebuffer, box_x, box_y, box_x2, box_y2, colors[color_index].color)) {
268                  fprintf(stderr, "Error: framebuffer draw failed while drawing %s\n", colors[color_index].name);
269                  gfx_framebuffer_unbind(&framebuffer);
270                  free(fb_storage);
271                  hal_display_deinitialize();
272                  return EXIT_FAILURE;
273              }
274
275              /* Placeholder for future text rendering API call:
276               * Draw centered text "Hello ECEN-5713" during rectangle phase.
277               */
278
279              if (!gfx_draw_pixel(&framebuffer, pixel_x, pixel_y, colors[pixel_color_index].color)) {
280                  fprintf(stderr, "Error: single-pixel draw failed at (%u,%u)\n", pixel_x, pixel_y);
281                  gfx_framebuffer_unbind(&framebuffer);
282                  free(fb_storage);
283                  hal_display_deinitialize();
284                  return EXIT_FAILURE;
285              }
286
287              if (!gfx_flush_dirty(&framebuffer)) {
288                  fprintf(stderr, "Error: dirty flush failed during rectangle phase\n");
289                  gfx_framebuffer_unbind(&framebuffer);
290                  free(fb_storage);
291                  hal_display_deinitialize();
292                  return EXIT_FAILURE;
293              }
294
295              color_index = (color_index + 1) % color_count;
296              pixel_color_index = (pixel_color_index + 1) % color_count;
297
298              rect_distance = (rect_distance + STEP_PIXELS) % rect_perimeter;
299              rect_travelled += STEP_PIXELS;
300
301              if (rect_travelled >= rect_perimeter) {
302                  uint32_t back_step = (2U * STEP_PIXELS) % rect_perimeter;
303                  rect_start_distance = (rect_start_distance + rect_perimeter - back_step) % rect_perimeter;
304                  rect_distance = rect_start_distance;
305                  rect_travelled = 0U;
306                  phase = DEMO_PHASE_FILLS_AFTER_RECT;
307                  phase_step = 0U;
308              }
309              break;
310          }
311
312          case DEMO_PHASE_FILLS_AFTER_RECT:
313          case DEMO_PHASE_FILLS_AFTER_STARBURST: {
314              int fill_color_index = (int)fill_color_cursor % color_count;
315              DEMO_DEBUG_PRINTF("  Full fill: %s\n", colors[fill_color_index].name);
316              if (!gfx_fill(&framebuffer, colors[fill_color_index].color) || !gfx_flush(&framebuffer)) {
317                  fprintf(stderr, "Error: full-screen fill failed while drawing %s\n", colors[fill_color_index].name);
318                  gfx_framebuffer_unbind(&framebuffer);
319                  free(fb_storage);
320                  hal_display_deinitialize();
321                  return EXIT_FAILURE;
322              }
323
324              fill_color_cursor++;
325              phase_step++;
326              usleep(FULL_FILL_HOLD_MS * 1000U);
327
328              if (phase_step >= FULL_FILL_SHOW_COUNT) {
329                  phase_step = 0U;
330                  if (phase == DEMO_PHASE_FILLS_AFTER_RECT) {
331                      phase = DEMO_PHASE_STARBURST;
332                      starburst_phase_started = false;
333                  } else {
334                      phase = DEMO_PHASE_RECTANGLE;
335                  }
336              }
337              continue;
338          }
339
340          case DEMO_PHASE_STARBURST: {
341              apply_frame_pacing = false;
342
343              if (!starburst_phase_started) {
344                  if (!gfx_fill(&framebuffer, COLOR_BLACK) || !gfx_flush(&framebuffer)) {
345                      fprintf(stderr, "Error: starburst phase clear failed\n");
346                      gfx_framebuffer_unbind(&framebuffer);
347                      free(fb_storage);
348                      hal_display_deinitialize();
349                      return EXIT_FAILURE;
350                  }
351                  starburst_phase_started = true;
352              }
353
354              uint32_t edge_pos;
355              uint16_t ray_x = 0U;
356              uint16_t ray_y = 0U;
357
358              if (phase_step < STARBURST_SHORT_RAYS) {
359                  edge_pos = (phase_step * short_perimeter) / STARBURST_SHORT_RAYS;
360                  rectangle_position_from_distance(edge_pos,
361                                                   short_left,
362                                                   short_top,
363                                                   short_right,
364                                                   short_bottom,
365                                                   &ray_x,
366                                                   &ray_y);
367              } else {
368                  uint32_t long_phase_step = phase_step - STARBURST_SHORT_RAYS;
369                  edge_pos = (long_phase_step * long_perimeter) / STARBURST_LONG_RAYS;
370                  rectangle_position_from_distance(edge_pos,
371                                                   long_left,
372                                                   long_top,
373                                                   long_right,
374                                                   long_bottom,
375                                                   &ray_x,
376                                                   &ray_y);
377              }
378
379              if (!gfx_draw_line(&framebuffer,
380                                 (int16_t)center_x,
381                                 (int16_t)center_y,
382                                 (int16_t)ray_x,
383                                 (int16_t)ray_y,
384                                 colors[color_index].color)) {
385                  fprintf(stderr, "Error: starburst line draw failed\n");
386                  gfx_framebuffer_unbind(&framebuffer);
387                  free(fb_storage);
388                  hal_display_deinitialize();
389                  return EXIT_FAILURE;
390              }
391
392              if (!gfx_draw_pixel(&framebuffer, pixel_x, pixel_y, colors[pixel_color_index].color)) {
393                  fprintf(stderr, "Error: single-pixel draw failed at (%u,%u)\n", pixel_x, pixel_y);
394                  gfx_framebuffer_unbind(&framebuffer);
395                  free(fb_storage);
396                  hal_display_deinitialize();
397                  return EXIT_FAILURE;
398              }
399
400              if (!gfx_flush_dirty(&framebuffer)) {
401                  fprintf(stderr, "Error: dirty flush failed during starburst phase\n");
402                  gfx_framebuffer_unbind(&framebuffer);
403                  free(fb_storage);
404                  hal_display_deinitialize();
405                  return EXIT_FAILURE;
406              }
407
408              color_index = (color_index + 1) % color_count;
409              pixel_color_index = (pixel_color_index + 1) % color_count;
410
411              phase_step++;
412              if (phase_step >= STARBURST_RAYS_TOTAL) {
413                  phase = DEMO_PHASE_FILLS_AFTER_STARBURST;
414                  phase_step = 0U;
415              }
416              break;
417          }
418
419          default:
420              phase = DEMO_PHASE_RECTANGLE;
421              phase_step = 0U;
422              break;
423          }
424
425          {
426              int32_t next_pixel_x = (int32_t)pixel_x + pixel_dx;
427              int32_t next_pixel_y = (int32_t)pixel_y + pixel_dy;
428
429              if (next_pixel_x < 0) {
430                  next_pixel_x = 0;

430                  next_pixel_x = 0;
431                  pixel_dx = (int16_t)(-pixel_dx);
432              } else if (next_pixel_x >= (int32_t)DISPLAY_WIDTH) {
433                  next_pixel_x = (int32_t)DISPLAY_WIDTH - 1;
434                  pixel_dx = (int16_t)(-pixel_dx);
435              }
436
437              if (next_pixel_y < 0) {
438                  next_pixel_y = 0;
439                  pixel_dy = (int16_t)(-pixel_dy);
440              } else if (next_pixel_y >= (int32_t)DISPLAY_HEIGHT) {
441                  next_pixel_y = (int32_t)DISPLAY_HEIGHT - 1;
442                  pixel_dy = (int16_t)(-pixel_dy);
443              }
444
445              pixel_x = (uint16_t)next_pixel_x;
446              pixel_y = (uint16_t)next_pixel_y;
447          }
448
449          if (apply_frame_pacing) {
450              sleep_remaining_frame(frame_start_ms, FRAME_DELAY_MS);
451          }
452      }
453
454      /* Unreachable in this demo */
455      gfx_framebuffer_unbind(&framebuffer);
456      free(fb_storage);
457      hal_display_deinitialize();
458
459      return EXIT_SUCCESS;
460  }
